// ═══════════════════════ CHATBOT ═══════════════════════
function ChatBot() {
  const [isOpen, setIsOpen] = useState(false);
  const [msgs, setMsgs] = useState([]);
  const [input, setInput] = useState("");
  const [prompt, setPrompt] = useState(false);
  const end = useRef(null);

  useEffect(() => { const t = setTimeout(()=>{ if(!isOpen) setPrompt(true); }, 25000); return ()=>clearTimeout(t); }, []);
  useEffect(() => { end.current?.scrollIntoView({ behavior:"smooth" }); }, [msgs]);

  const open = () => {
    setIsOpen(true); setPrompt(false);
    if (!msgs.length) setMsgs([{ from:"bot", text:"Hi, I'm Eric Willie's AI assistant. I can help you schedule a free consultation or answer general questions about our family law services. How can I help?" }]);
  };

  const send = () => {
    if (!input.trim()) return;
    const q = input.trim(); setInput("");
    setMsgs(p=>[...p, { from:"user", text:q }]);
    setTimeout(()=>{
      const l = q.toLowerCase();
      let r = "That's a great question for Eric to address directly. Would you like to schedule a free consultation? You can also call (512) 478-0834.";
      if (l.match(/consult|appoint|schedule|meet/)) r = "I'd love to help schedule your free consultation. Could you share your name, phone number, and the type of family law matter? Eric's team responds within minutes.";
      else if (l.match(/cost|price|fee|afford|much/)) r = "Eric offers a free initial consultation to discuss your situation and give a clear picture of costs. Every case is different. Would you like to schedule one?";
      else if (l.match(/custod|kids|child/)) r = "Eric has extensive custody experience in Travis, Williamson, and Hays counties. He handles conservatorship, possession, modifications, and enforcement. Want to schedule a free consultation?";
      else if (l.match(/divorce/)) r = "Eric handles all types — contested, uncontested, military, high-net-worth, and LGBTQ. Over 20 years of Austin experience. Want to set up a free consultation?";
      else if (l.match(/human|person|real|speak/)) r = "Absolutely. I'm an AI assistant for Eric M. Willie, P.C. Call (512) 478-0834 to speak with Eric's team, or I can have them call you within minutes.";
      else if (l.match(/español|spanish|habla/)) r = "¡Sí! El equipo de Eric habla español. Puede llamar al (512) 478-0834 o puedo programar una consulta gratuita. ¿Cómo puedo ayudarle?";
      setMsgs(p=>[...p, { from:"bot", text:r }]);
    }, 700);
  };

  return (
    <>
      {prompt && !isOpen && (
        <div onClick={open} style={{ position:"fixed", bottom:84, right:20, zIndex:999, background:C.surface, border:`1px solid ${C.goldBorder}`, borderRadius:14, padding:"14px 18px", maxWidth:290, cursor:"pointer", boxShadow:"0 8px 32px rgba(0,0,0,0.12)" }}>
          <p style={{ color:C.text, fontSize:14, margin:0, lineHeight:1.5 }}>Going through a difficult time? Eric has helped thousands of Austin families. <span style={{ color:C.gold, fontWeight:700 }}>Chat with us →</span></p>
          <button onClick={e=>{ e.stopPropagation(); setPrompt(false); }} style={{ position:"absolute", top:6, right:10, background:"none", border:"none", color:C.text3, fontSize:18, cursor:"pointer" }}>×</button>
        </div>
      )}
      {isOpen && (
        <div style={{ position:"fixed", bottom:84, right:20, zIndex:1000, width:370, maxWidth:"calc(100vw - 40px)", height:500, maxHeight:"65vh", background:C.surface, border:`1px solid ${C.border}`, borderRadius:14, display:"flex", flexDirection:"column", boxShadow:"0 12px 48px rgba(0,0,0,0.15)", overflow:"hidden" }}>
          <div style={{ padding:"14px 18px", background:C.navy, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
            <div>
              <p style={{ color:"#fff", fontSize:14, fontWeight:700, margin:0 }}>Eric Willie's Office</p>
              <p style={{ color:C.green, fontSize:11, margin:0, fontWeight:500 }}>● Online — Responds instantly</p>
            </div>
            <button onClick={()=>setIsOpen(false)} style={{ background:"none", border:"none", color:"rgba(255,255,255,0.6)", fontSize:22, cursor:"pointer" }}>×</button>
          </div>
          <div style={{ flex:1, overflow:"auto", padding:16, display:"flex", flexDirection:"column", gap:8, background:C.bg }}>
            {msgs.map((m,i)=>(
              <div key={i} style={{ alignSelf:m.from==="user"?"flex-end":"flex-start", background:m.from==="user"?C.navy:C.surface, color:m.from==="user"?"#fff":C.text, padding:"10px 14px", borderRadius:m.from==="user"?"14px 14px 4px 14px":"14px 14px 14px 4px", maxWidth:"82%", fontSize:13.5, lineHeight:1.5, border:m.from==="bot"?`1px solid ${C.borderLight}`:"none" }}>
                {m.text}
              </div>
            ))}
            <div ref={end} />
          </div>
          <div style={{ padding:12, borderTop:`1px solid ${C.borderLight}`, display:"flex", gap:8, background:C.surface }}>
            <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>e.key==="Enter"&&send()} placeholder="Type a message…" style={{ flex:1, padding:"11px 14px", background:C.bg, border:`1px solid ${C.borderLight}`, color:C.text, fontSize:14, borderRadius:8, outline:"none" }} />
            <button onClick={send} style={{ padding:"11px 18px", background:C.gold, border:"none", color:C.white, fontWeight:700, borderRadius:8, cursor:"pointer", fontSize:13 }}>Send</button>
          </div>
        </div>
      )}
      <button onClick={open} aria-label="Chat with us" style={{ position:"fixed", bottom:20, right:20, zIndex:998, width:58, height:58, borderRadius:29, border:"none", background:C.gold, color:C.white, fontSize:14, cursor:"pointer", boxShadow:"0 4px 20px rgba(184,150,62,0.35)", display:"flex", alignItems:"center", justifyContent:"center", transition:"transform 0.2s", fontWeight:700 }}>
        {isOpen ? "✕" : <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>}
      </button>
    </>
  );
}

